/**
 * Public booking widget — Rubitime-style.
 * Multi-step: pick track → pick available slot → fill contact → confirm.
 * Mounted at /book. No auth required.
 */

import { useEffect, useMemo, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import PlatformShell from '../components/PlatformShell'
import { api } from '../api/client'
import { setAccessToken } from '../lib/authStorage'
import { saveSession } from '../lib/auth'

type Step = 'track' | 'slot' | 'contact' | 'done'
type Track = 'python' | 'scratch' | 'vibe'

interface SlotLike {
  id: string
  datetime: string
  durationMin: number
  teacherId: string
}

interface ReserveResponse {
  guestToken: string
  leadId: string
  slotId: string
  accessToken?: string
}

const TRACKS: { id: Track; emoji: string; title: string; tagline: string; bg: string; ink: string }[] = [
  { id: 'python',  emoji: '🐍', title: 'Python',       tagline: 'Программирование с черепашкой', bg: 'var(--sky-soft, #e0f2fe)',    ink: 'var(--sky-ink, #075985)'    },
  { id: 'scratch', emoji: '🎮', title: 'Scratch',      tagline: '2 игры за первое занятие',      bg: 'var(--orange-soft, #fed7aa)', ink: 'var(--orange-ink, #9a3412)' },
  { id: 'vibe',    emoji: '🌐', title: 'Vibe-coding',  tagline: 'Свой сайт за 1 час',            bg: 'var(--pink-soft, #fce7f3)',   ink: 'var(--pink-ink, #9d174d)'   },
]

export default function Booking() {
  const navigate = useNavigate()

  const [step, setStep] = useState<Step>('track')
  const [track, setTrack] = useState<Track>('python')

  // Slots
  const [slots, setSlots] = useState<SlotLike[]>([])
  const [slotsLoading, setSlotsLoading] = useState(false)
  const [pickedSlotId, setPickedSlotId] = useState<string>('')

  // Contact
  const [parentName, setParentName] = useState('')
  const [parentPhone, setParentPhone] = useState('')
  const [parentEmail, setParentEmail] = useState('')
  const [childName, setChildName] = useState('')
  const [childAge, setChildAge] = useState<number>(10)
  const [submitting, setSubmitting] = useState(false)
  const [error, setError] = useState('')

  const [done, setDone] = useState<ReserveResponse | null>(null)

  function loadSlots() {
    setSlotsLoading(true)
    setError('')
    const now = new Date()
    const in14 = new Date(now.getTime() + 14 * 86400000)
    api.post<SlotLike[]>('/booking/public/check-availability', {
      from: now.toISOString(),
      to: in14.toISOString(),
      track,
    })
      .then(setSlots)
      .catch((e: Error) => setError(e.message || 'Не удалось загрузить слоты. Попробуйте позже.'))
      .finally(() => setSlotsLoading(false))
  }

  useEffect(() => {
    if (step === 'slot') loadSlots()
  }, [step, track])

  const slotsByDay = useMemo(() => {
    const m = new Map<string, SlotLike[]>()
    for (const s of slots) {
      const d = new Date(s.datetime).toISOString().slice(0, 10)
      const arr = m.get(d) ?? []
      arr.push(s)
      m.set(d, arr)
    }
    return Array.from(m.entries()).sort(([a], [b]) => a.localeCompare(b))
  }, [slots])

  const pickedSlot = useMemo(() => slots.find(s => s.id === pickedSlotId), [slots, pickedSlotId])

  async function handleSubmit() {
    if (!parentName.trim() || !parentPhone.trim()) {
      setError('Имя и телефон родителя обязательны')
      return
    }
    if (!pickedSlotId) {
      setError('Слот не выбран')
      setStep('slot')
      return
    }
    setSubmitting(true)
    setError('')
    try {
      const res = await api.post<ReserveResponse>('/booking/public/reserve', {
        slotId: pickedSlotId,
        parentName: parentName.trim(),
        parentPhone: parentPhone.trim(),
        parentEmail: parentEmail.trim(),
        childName: childName.trim(),
        childAge,
        track,
      })
      // Login as guest immediately so родитель видит свой кабинет
      if (res.accessToken) {
        setAccessToken(res.accessToken)
        saveSession({ role: 'guest', name: parentName.trim() || 'Гость' })
      }
      setDone(res)
      setStep('done')
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Ошибка бронирования')
    } finally {
      setSubmitting(false)
    }
  }

  return (
    <PlatformShell>
      <div style={{ maxWidth: 720, margin: '40px auto', padding: '0 20px' }}>

        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: 32 }}>
          <h1 style={{ fontFamily: 'var(--f-display)', fontSize: 'clamp(28px, 5vw, 40px)', fontWeight: 900, margin: '0 0 8px', color: 'var(--ink)' }}>
            Запишись на пробное занятие
          </h1>
          <p style={{ fontSize: 16, color: 'var(--ink-soft)', margin: 0 }}>
            Бесплатно · 60 минут · Без подготовки
          </p>
        </div>

        {/* Progress */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
          {(['track', 'slot', 'contact', 'done'] as Step[]).map((s, i) => {
            const labels = ['Трек', 'Время', 'Контакты', 'Готово']
            const visited = (['track','slot','contact','done'] as Step[]).indexOf(step) >= i
            return (
              <div key={s} style={{
                flex: 1, height: 6, borderRadius: 3,
                background: visited ? 'var(--violet, #6b5ce7)' : 'var(--paper-3, #e5e2f0)',
                position: 'relative',
              }}>
                <div style={{ position: 'absolute', top: 12, left: 0, fontSize: 11, color: visited ? 'var(--violet)' : 'var(--ink-soft)', fontWeight: 700 }}>
                  {labels[i]}
                </div>
              </div>
            )
          })}
        </div>

        <div style={{ marginTop: 40 }}>

          {/* Step 1: Track */}
          {step === 'track' && (
            <div className="kb-card" style={{ padding: 28 }}>
              <h2 style={{ margin: '0 0 18px', fontSize: 20, fontWeight: 800 }}>Что хочешь изучать?</h2>
              <div style={{ display: 'grid', gap: 12 }}>
                {TRACKS.map(t => (
                  <button key={t.id} onClick={() => setTrack(t.id)}
                    style={{
                      display: 'flex', alignItems: 'center', gap: 16, padding: 16, borderRadius: 14,
                      border: track === t.id ? '2.5px solid var(--violet)' : '2.5px solid transparent',
                      background: t.bg, cursor: 'pointer', textAlign: 'left',
                    }}>
                    <div style={{ fontSize: 36 }}>{t.emoji}</div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontFamily: 'var(--f-display)', fontWeight: 900, fontSize: 18, color: t.ink }}>{t.title}</div>
                      <div style={{ fontSize: 13, color: t.ink, opacity: 0.8 }}>{t.tagline}</div>
                    </div>
                    {track === t.id && <div style={{ fontSize: 24 }}>✅</div>}
                  </button>
                ))}
              </div>
              <button className="kb-btn" style={{ marginTop: 20, width: '100%', background: 'var(--violet)', color: '#fff', fontSize: 15, padding: '12px 0', fontWeight: 800 }}
                onClick={() => setStep('slot')}>
                Выбрать время →
              </button>
            </div>
          )}

          {/* Step 2: Slot */}
          {step === 'slot' && (
            <div className="kb-card" style={{ padding: 28 }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 18 }}>
                <h2 style={{ margin: 0, fontSize: 20, fontWeight: 800 }}>Выбери удобное время</h2>
                <button className="kb-btn" style={{ fontSize: 12 }} onClick={() => setStep('track')}>← Назад</button>
              </div>

              {error && <div style={{ background: '#fee', color: '#c00', padding: 12, borderRadius: 8, marginBottom: 12, fontSize: 13 }}>{error}</div>}

              {slotsLoading ? (
                <div style={{ padding: 30, textAlign: 'center', color: 'var(--ink-soft)' }}>Загрузка свободных слотов…</div>
              ) : slotsByDay.length === 0 ? (
                <div style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>
                  Свободных слотов на ближайшие 14 дней нет. Напишите нам в WhatsApp +7 (985) XXX-XX-XX — подберём вручную.
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 14, maxHeight: 460, overflowY: 'auto' }}>
                  {slotsByDay.map(([date, dSlots]) => (
                    <div key={date}>
                      <div style={{ fontSize: 13, fontWeight: 800, color: 'var(--ink-soft)', marginBottom: 6, textTransform: 'capitalize' }}>
                        {new Date(date).toLocaleDateString('ru-RU', { weekday: 'long', day: 'numeric', month: 'long' })}
                      </div>
                      <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                        {dSlots.map(s => {
                          const time = new Date(s.datetime).toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' })
                          const picked = pickedSlotId === s.id
                          return (
                            <button key={s.id} onClick={() => setPickedSlotId(s.id)}
                              style={{
                                padding: '8px 14px', borderRadius: 8, fontWeight: 700, fontSize: 14, cursor: 'pointer',
                                border: picked ? '2px solid var(--violet)' : '1.5px solid var(--paper-3)',
                                background: picked ? 'var(--violet)' : '#fff',
                                color: picked ? '#fff' : 'var(--ink)',
                              }}>
                              {time}
                            </button>
                          )
                        })}
                      </div>
                    </div>
                  ))}
                </div>
              )}

              <button className="kb-btn"
                style={{ marginTop: 20, width: '100%', background: 'var(--violet)', color: '#fff', fontSize: 15, padding: '12px 0', fontWeight: 800, opacity: pickedSlotId ? 1 : 0.4 }}
                disabled={!pickedSlotId}
                onClick={() => setStep('contact')}>
                Дальше →
              </button>
            </div>
          )}

          {/* Step 3: Contact */}
          {step === 'contact' && (
            <div className="kb-card" style={{ padding: 28 }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 18 }}>
                <h2 style={{ margin: 0, fontSize: 20, fontWeight: 800 }}>Куда отправить подтверждение?</h2>
                <button className="kb-btn" style={{ fontSize: 12 }} onClick={() => setStep('slot')}>← Назад</button>
              </div>

              {pickedSlot && (
                <div style={{ padding: 12, background: 'var(--violet-soft, #f3f0ff)', borderRadius: 8, fontSize: 13, marginBottom: 18 }}>
                  📅 Вы выбрали:&nbsp;
                  <b>{new Date(pickedSlot.datetime).toLocaleString('ru-RU', { weekday: 'long', day: 'numeric', month: 'long', hour: '2-digit', minute: '2-digit' })}</b>
                  &nbsp;· {pickedSlot.durationMin} мин · трек {track}
                </div>
              )}

              <div style={{ display: 'grid', gap: 12 }}>
                <div>
                  <label style={lbl}>Ваше имя *</label>
                  <input style={inp} value={parentName} onChange={e => setParentName(e.target.value)} placeholder="Анна" />
                </div>
                <div>
                  <label style={lbl}>Телефон *</label>
                  <input style={inp} type="tel" value={parentPhone} onChange={e => setParentPhone(e.target.value)} placeholder="+7..." />
                </div>
                <div>
                  <label style={lbl}>Email</label>
                  <input style={inp} type="email" value={parentEmail} onChange={e => setParentEmail(e.target.value)} placeholder="for-confirmation@..." />
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: 12 }}>
                  <div>
                    <label style={lbl}>Имя ребёнка</label>
                    <input style={inp} value={childName} onChange={e => setChildName(e.target.value)} />
                  </div>
                  <div>
                    <label style={lbl}>Возраст</label>
                    <input style={inp} type="number" min={5} max={18} value={childAge} onChange={e => setChildAge(Number(e.target.value))} />
                  </div>
                </div>
              </div>

              {error && <div style={{ marginTop: 12, color: '#c00', fontSize: 13 }}>{error}</div>}

              <button className="kb-btn"
                style={{ marginTop: 20, width: '100%', background: 'var(--violet)', color: '#fff', fontSize: 15, padding: '14px 0', fontWeight: 800 }}
                onClick={() => void handleSubmit()} disabled={submitting}>
                {submitting ? 'Бронируем…' : 'Записаться →'}
              </button>

              <div style={{ marginTop: 12, fontSize: 11, color: 'var(--ink-soft)', textAlign: 'center', lineHeight: 1.5 }}>
                Нажимая «Записаться», вы соглашаетесь с <a href="/legal/privacy">политикой конфиденциальности</a>.
              </div>
            </div>
          )}

          {/* Step 4: Done */}
          {step === 'done' && done && (
            <div className="kb-card" style={{ padding: 40, textAlign: 'center', background: 'var(--mint-soft, #d1fae5)' }}>
              <div style={{ fontSize: 64, marginBottom: 16 }}>🎉</div>
              <h2 style={{ margin: '0 0 12px', fontSize: 24, fontWeight: 900, color: 'var(--mint-ink, #065f46)' }}>
                Готово!
              </h2>
              <p style={{ fontSize: 15, color: 'var(--mint-ink, #065f46)', marginBottom: 8, lineHeight: 1.6 }}>
                {pickedSlot && (
                  <><b>{new Date(pickedSlot.datetime).toLocaleString('ru-RU', { weekday: 'long', day: 'numeric', month: 'long', hour: '2-digit', minute: '2-digit' })}</b><br/></>
                )}
                Мы отправим SMS-напоминание за день и за час до занятия.
              </p>
              {parentEmail && (
                <p style={{ fontSize: 13, color: 'var(--mint-ink, #065f46)', opacity: 0.8 }}>
                  Подтверждение и ссылка на занятие → на {parentEmail}
                </p>
              )}
              <div style={{ marginTop: 24, display: 'flex', gap: 8, justifyContent: 'center' }}>
                <button className="kb-btn" onClick={() => navigate('/guest')}>На главную</button>
                {done.guestToken && (
                  <button className="kb-btn" style={{ background: 'var(--violet)', color: '#fff' }}
                    onClick={() => navigate(`/join/${done.guestToken}`)}>
                    → В личный кабинет
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </PlatformShell>
  )
}

const lbl: React.CSSProperties = { display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: 'uppercase', color: 'var(--ink-soft)', marginBottom: 4 }
const inp: React.CSSProperties = { width: '100%', padding: '10px 12px', borderRadius: 8, border: '1.5px solid var(--paper-3)', fontSize: 15, fontFamily: 'inherit', boxSizing: 'border-box' }
